  limit: number = MESSAGE_PAGE_SIZE,
): Promise<Message[]> {
  const rows = await query<MessageRow>(
    "SELECT * FROM messages WHERE chat_id = $1 AND created_at < $2 ORDER BY created_at DESC LIMIT $3",
